import java.util.*;class P1{public static void main(String[] a){Scanner s=new Scanner(System.in);double[] sal=new double[10],yrs=new double[10],bonus=new double[10],newsal=new double[10];double tb=0,old=0,nw=0;for(int i=0;i<10;i++){sal[i]=s.nextDouble();yrs[i]=s.nextDouble();if(sal[i]<=0||yrs[i]<0){i--;continue;}}for(int i=0;i<10;i++){if(yrs[i]>5)bonus[i]=sal[i]*0.05;else bonus[i]=sal[i]*0.02;newsal[i]=sal[i]+bonus[i];tb+=bonus[i];old+=sal[i];nw+=newsal[i];}System.out.println(tb);System.out.println(old);System.out.println(nw);}}